package ir.tahamohamadi.publication; import ir.tahamohamadi.common.domain.*; import org.springframework.data.domain.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.*; public interface PublicationTranslationRepository extends JpaRepository<PublicationTranslation,UUID>{ List<PublicationTranslation> findByPublicationIdAndDeletedAtIsNull(UUID publicationId); List<PublicationTranslation> findByPublicationIdInAndDeletedAtIsNull(Collection<UUID> publicationIds); @Query(value="select t from PublicationTranslation t join fetch t.publication p where t.languageCode=:language and t.deletedAt is null and p.deletedAt is null and p.contentStatus='PUBLISHED' and (:stage is null or p.publicationStage=:stage)",countQuery="select count(t) from PublicationTranslation t join t.publication p where t.languageCode=:language and t.deletedAt is null and p.deletedAt is null and p.contentStatus='PUBLISHED' and (:stage is null or p.publicationStage=:stage)") Page<PublicationTranslation> findPublishedByLanguage(@Param("language") LanguageCode language,@Param("stage") PublicationStage stage,Pageable page); @Query("select t from PublicationTranslation t join fetch t.publication p where t.languageCode=:language and lower(t.slug)=lower(:slug) and t.deletedAt is null and p.deletedAt is null and p.contentStatus='PUBLISHED'") Optional<PublicationTranslation> findPublishedByLanguageAndSlug(@Param("language") LanguageCode language,@Param("slug") String slug); }
